displayCss:
.user-css .table-striped {
 background-color: transparent;
 table-layout: fixed;
}

.user-css .table-striped td {
 background-color: transparent;
 border-top: 0;
 width: 12.5%;
}

.user-css .table-striped td h3 {
 font-size: 12px;
 white-space: nowrap;
}

.user-css .table-striped tr:nth-child(odd) {
 background-color: transparent;
}

.user-css .table-striped tr:nth-child(even) {
 background-color: transparent;
}

.user-css .table-striped td .artist-credits {
 display: none;
}
